              code: `# Dockerfile\nFROM python:3.11-slim\nWORKDIR /app\nCOPY requirements.txt .\nRUN pip install --no-cache-dir -r requirements.txt\nCOPY . .\nEXPOSE 8000\nCMD ["gunicorn", "-w", "4", "-b", "0.0.0.0:8000", "app:app"]`,
              takeaway: 'Always copy `requirements.txt` and install deps BEFORE copying code — Docker caches that layer, making iteration 100× faster.',
