export const getTotals = () => {
  let topics = 0
  let projects = 0
  let hours = 0
  for (const m of curriculum.modules) {
    hours += m.hours
    projects += m.projects.length
    for (const s of m.sections) topics += s.topics.length
  }
  return { topics, projects, hours, modules: curriculum.modules.length }
}

export const flattenTopics = () => {
  const out = []
  for (const m of curriculum.modules) {
    for (const s of m.sections) {
      for (const t of s.topics) {
        out.push({
          id: t.id,
          title: t.title,
          moduleId: m.id,
          moduleTitle: m.title,
          sectionId: s.id,
          sectionTitle: s.title,
        })
      }
    }
  }
  return out
}
